#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char S[105]; scanf("%s",S);
        char email[105]; scanf("%s",email);
        // password
        char pwd[105]; strncpy(pwd,S,N); pwd[N]='\0';
        int hasDigit=0, hasSpecial=0;
        for(int i=0;i<N;i++){
            if(isdigit((unsigned char)pwd[i])) hasDigit=1;
            else if(!isalnum((unsigned char)pwd[i])) hasSpecial=1;
        }
        // username
        char *at=strchr(email,'@');
        int len = at ? (int)(at-email) : (int)strlen(email);
        char uname[105]; int idx=0;
        for(int i=0;i<len;i++){
            char c=email[i];
            if(isalnum((unsigned char)c)) uname[idx++]=c; else uname[idx++]='_';
        }
        uname[idx]='\0';
        if(idx> N) uname[N]='\0';
        // output
        printf("%s\n",pwd);
        printf("%s\n", hasDigit?"YES":"NO");
        printf("%s\n", hasSpecial?"YES":"NO");
        printf("%s\n", uname);
    }
    return 0;
}

