#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        string S; cin>>S;
        string email; cin>>email;
        string pwd = S.substr(0,N);
        bool hasDigit=false, hasSpecial=false;
        for(char c:pwd){
            unsigned char uc = static_cast<unsigned char>(c);
            if(isdigit(uc)) hasDigit=true;
            else if(!isalnum(uc)) hasSpecial=true;
        }
        size_t atPos = email.find('@');
        string local = email.substr(0, atPos);
        for(char &c: local){
            unsigned char uc = static_cast<unsigned char>(c);
            if(!isalnum(uc)) c='_';
        }
        if((int)local.size()>N) local.resize(N);
        cout<<pwd<<"\n";
        cout<<(hasDigit?"YES":"NO")<<"\n";
        cout<<(hasSpecial?"YES":"NO")<<"\n";
        cout<<local<<"\n";
    }
    return 0;
}

