import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            String email = br.readLine().trim();
            String pwd = S.substring(0, N);
            boolean hasDigit = false, hasSpecial = false;
            for (char c : pwd.toCharArray()) {
                if (Character.isDigit(c)) hasDigit = true;
                else if (!Character.isLetterOrDigit(c)) hasSpecial = true;
            }
            int at = email.indexOf('@');
            String local = at == -1 ? email : email.substring(0, at);
            StringBuilder uname = new StringBuilder();
            for (char c : local.toCharArray()) {
                if (Character.isLetterOrDigit(c)) uname.append(c);
                else uname.append('_');
            }
            if (uname.length() > N) uname.setLength(N);
            out.append(pwd).append('\n');
            out.append(hasDigit ? "YES" : "NO").append('\n');
            out.append(hasSpecial ? "YES" : "NO").append('\n');
            out.append(uname.toString()).append('\n');
        }
        System.out.print(out.toString());
    }
}

