const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split('\n');
let ptr = 0;
const T = parseInt(input[ptr++].trim(),10);
let out = [];
for(let tc=0; tc<T; tc++){
  const N = parseInt(input[ptr++].trim(),10);
  const S = input[ptr++].trim();
  const email = input[ptr++].trim();
  const pwd = S.slice(0,N);
  let hasDigit = false, hasSpecial = false;
  for(const ch of pwd){
    if(ch >= '0' && ch <= '9') hasDigit = true;
    else if(!(/[a-zA-Z0-9]/.test(ch))) hasSpecial = true;
  }
  const atPos = email.indexOf('@');
  const local = atPos === -1 ? email : email.slice(0, atPos);
  let uname = '';
  for(const ch of local){
    if(/[a-zA-Z0-9]/.test(ch)) uname += ch; else uname += '_';
  }
  if(uname.length > N) uname = uname.slice(0,N);
  out.push(pwd);
  out.push(hasDigit ? 'YES' : 'NO');
  out.push(hasSpecial ? 'YES' : 'NO');
  out.push(uname);
}
console.log(out.join('\n'));

